class SwissMode(enum.Enum):
    
    EMA = 0
    
    SMA = 1
    
    GAUSS = 2
    
    BUTTERWORTH = 3
    
    SMOOTH = 4
    
    HIGH_PASS = 5
    
    TWO_POLE_HIGH_PASS = 6
    
    BAND_PASS = 7
    
    BAND_STOP = 8
    


class _UniffiFfiConverterTypeSwissMode(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return SwissMode.EMA
        if variant == 2:
            return SwissMode.SMA
        if variant == 3:
            return SwissMode.GAUSS
        if variant == 4:
            return SwissMode.BUTTERWORTH
        if variant == 5:
            return SwissMode.SMOOTH
        if variant == 6:
            return SwissMode.HIGH_PASS
        if variant == 7:
            return SwissMode.TWO_POLE_HIGH_PASS
        if variant == 8:
            return SwissMode.BAND_PASS
        if variant == 9:
            return SwissMode.BAND_STOP
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == SwissMode.EMA:
            return
        if value == SwissMode.SMA:
            return
        if value == SwissMode.GAUSS:
            return
        if value == SwissMode.BUTTERWORTH:
            return
        if value == SwissMode.SMOOTH:
            return
        if value == SwissMode.HIGH_PASS:
            return
        if value == SwissMode.TWO_POLE_HIGH_PASS:
            return
        if value == SwissMode.BAND_PASS:
            return
        if value == SwissMode.BAND_STOP:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == SwissMode.EMA:
            buf.write_i32(1)
        if value == SwissMode.SMA:
            buf.write_i32(2)
        if value == SwissMode.GAUSS:
            buf.write_i32(3)
        if value == SwissMode.BUTTERWORTH:
            buf.write_i32(4)
        if value == SwissMode.SMOOTH:
            buf.write_i32(5)
        if value == SwissMode.HIGH_PASS:
            buf.write_i32(6)
        if value == SwissMode.TWO_POLE_HIGH_PASS:
            buf.write_i32(7)
        if value == SwissMode.BAND_PASS:
            buf.write_i32(8)
        if value == SwissMode.BAND_STOP:
            buf.write_i32(9)




